"use client";
import React, { useState } from 'react';
import { Phone, Mail, MapPin, Clock, Send, User, MessageSquare, Leaf, Sprout, Facebook, Twitter, Instagram, Building, Globe } from 'lucide-react';

export default function ContactPage() {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    subject: '',
    message: ''
  });

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log('Form submitted:', formData);
    alert('धन्यवाद! हम जल्द ही आपसे संपर्क करेंगे। Thank you! We will contact you soon.');
  };

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const contactInfo = [
    {
      icon: <Phone className="w-8 h-8" />,
      title: "Phone Number",
      titleHindi: "फोन नंबर",
      details: ["+91 7987279783"],
      color: "green"
    },
    {
      icon: <Mail className="w-8 h-8" />,
      title: "Email Address",
      titleHindi: "ईमेल पता",
      details: ["morvicropscience@gmail.com"],
      color: "orange"
    },
    {
      icon: <MapPin className="w-8 h-8" />,
      title: "Office Locations",
      titleHindi: "कार्यालय स्थान",
      details: [
        "Samudragarh, Purba Burdwan, West Bengal",
        "Ambikapur, Surguja, Chhattisgarh"
      ],
      color: "green"
    },
    {
      icon: <Clock className="w-8 h-8" />,
      title: "Working Hours",
      titleHindi: "कार्य समय",
      details: ["Mon - Sat: 9:00 AM - 6:00 PM", "Sunday: Closed"],
      color: "orange"
    }
  ];

  const officeLocations = [
    {
      title: "West Bengal Office",
      titleHindi: "पश्चिम बंगाल कार्यालय",
      address: "Samudragarh, Purba Burdwan",
      state: "West Bengal",
      type: "Operational Headquarters"
    },
    {
      title: "Chhattisgarh Office",
      titleHindi: "छत्तीसगढ़ कार्यालय",
      address: "Ambikapur, Surguja District",
      state: "Chhattisgarh",
      type: "Registered Office"
    }
  ];

  return (
    <div className="min-h-screen bg-white">
      {/* Hero Section */}
      <section className="relative bg-gradient-to-br from-green-600 via-green-500 to-[#ff9c00] text-white py-24 overflow-hidden">
        <div className="absolute inset-0 opacity-10">
          <Sprout className="absolute top-10 left-10 w-32 h-32 animate-pulse" />
          <Leaf className="absolute bottom-10 right-10 w-40 h-40 animate-pulse" style={{ animationDelay: '1s' }} />
          <Sprout className="absolute top-1/2 right-1/4 w-24 h-24 animate-pulse" style={{ animationDelay: '2s' }} />
        </div>

        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative z-10">
          <div className="text-center">
            <h1 className="text-5xl md:text-6xl font-bold mb-4">
              Contact Us
            </h1>
            <p className="text-3xl font-semibold text-green-100 mb-6">
              हमसे संपर्क करें
            </p>
            <p className="text-xl max-w-3xl mx-auto">
              Get in touch with us for quality agricultural solutions
            </p>
          </div>
        </div>
      </section>

      {/* Contact Info Cards */}
      <section className="py-20 bg-gradient-to-br from-gray-50 to-white relative">
        <div className="absolute top-10 right-10 w-64 h-64 bg-gradient-to-br from-green-200 to-[#ff9c00] opacity-10 rounded-full blur-3xl"></div>
        <div className="absolute bottom-10 left-10 w-48 h-48 bg-gradient-to-br from-[#ff9c00] to-green-200 opacity-10 rounded-full blur-3xl"></div>

        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative z-10">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {contactInfo.map((info, idx) => (
              <div 
                key={idx} 
                className={`bg-white p-6 rounded-2xl shadow-md hover:shadow-2xl transition-all transform hover:-translate-y-2 border-t-4 ${
                  info.color === 'green' ? 'border-green-600' : 'border-[#ff9c00]'
                }`}
              >
                <div className={`w-16 h-16 bg-gradient-to-br ${
                  info.color === 'green' ? 'from-green-100 to-green-200' : 'from-orange-100 to-orange-200'
                } rounded-full flex items-center justify-center ${
                  info.color === 'green' ? 'text-green-600' : 'text-[#ff9c00]'
                } mb-4`}>
                  {info.icon}
                </div>
                <h3 className="text-xl font-bold text-gray-900 mb-1">{info.title}</h3>
                <p className="text-sm text-[#ff9c00] font-semibold mb-3">{info.titleHindi}</p>
                <div className="space-y-2">
                  {info.details.map((detail, i) => (
                    <p key={i} className="text-gray-600 text-sm leading-relaxed">{detail}</p>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Contact Form & Map Section */}
      <section className="py-20 bg-white">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
            {/* Contact Form */}
            <div>
              <div className="mb-8">
                <h2 className="text-4xl font-bold text-gray-900 mb-2">Send Us a Message</h2>
                <p className="text-2xl text-[#ff9c00] font-semibold mb-4">हमें संदेश भेजें</p>
                <p className="text-gray-600">
                  Fill out the form below and we'll get back to you as soon as possible
                </p>
              </div>

              <div className="space-y-6">
                <div>
                  <label className="block text-gray-700 font-semibold mb-2">
                    Your Name / आपका नाम <span className="text-red-500">*</span>
                  </label>
                  <div className="relative">
                    <User className="absolute left-3 top-3.5 w-5 h-5 text-gray-400" />
                    <input
                      type="text"
                      name="name"
                      value={formData.name}
                      onChange={handleChange}
                      className="w-full pl-12 pr-4 py-3 border-2 border-gray-300 rounded-lg focus:border-green-600 focus:outline-none transition-colors"
                      placeholder="Enter your name"
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-gray-700 font-semibold mb-2">
                    Email Address / ईमेल पता <span className="text-red-500">*</span>
                  </label>
                  <div className="relative">
                    <Mail className="absolute left-3 top-3.5 w-5 h-5 text-gray-400" />
                    <input
                      type="email"
                      name="email"
                      value={formData.email}
                      onChange={handleChange}
                      className="w-full pl-12 pr-4 py-3 border-2 border-gray-300 rounded-lg focus:border-green-600 focus:outline-none transition-colors"
                      placeholder="your@email.com"
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-gray-700 font-semibold mb-2">
                    Phone Number / फोन नंबर <span className="text-red-500">*</span>
                  </label>
                  <div className="relative">
                    <Phone className="absolute left-3 top-3.5 w-5 h-5 text-gray-400" />
                    <input
                      type="tel"
                      name="phone"
                      value={formData.phone}
                      onChange={handleChange}
                      className="w-full pl-12 pr-4 py-3 border-2 border-gray-300 rounded-lg focus:border-green-600 focus:outline-none transition-colors"
                      placeholder="+91 XXXXXXXXXX"
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-gray-700 font-semibold mb-2">
                    Subject / विषय <span className="text-red-500">*</span>
                  </label>
                  <input
                    type="text"
                    name="subject"
                    value={formData.subject}
                    onChange={handleChange}
                    className="w-full px-4 py-3 border-2 border-gray-300 rounded-lg focus:border-green-600 focus:outline-none transition-colors"
                    placeholder="How can we help you?"
                  />
                </div>

                <div>
                  <label className="block text-gray-700 font-semibold mb-2">
                    Message / संदेश <span className="text-red-500">*</span>
                  </label>
                  <div className="relative">
                    <MessageSquare className="absolute left-3 top-3 w-5 h-5 text-gray-400" />
                    <textarea
                      name="message"
                      value={formData.message}
                      onChange={handleChange}
                      rows={5}
                      className="w-full pl-12 pr-4 py-3 border-2 border-gray-300 rounded-lg focus:border-green-600 focus:outline-none transition-colors resize-none"
                      placeholder="Write your message here..."
                    ></textarea>
                  </div>
                </div>

                <button
                  onClick={handleSubmit}
                  className="w-full bg-gradient-to-r from-green-600 to-[#ff9c00] text-white py-4 rounded-lg font-semibold hover:from-green-700 hover:to-[#ff8800] transition-all transform hover:scale-105 shadow-lg flex items-center justify-center gap-2"
                >
                  <Send className="w-5 h-5" />
                  Send Message / संदेश भेजें
                </button>
              </div>
            </div>

            {/* Office Locations & Info */}
            <div className="space-y-8">
              {/* Office Cards */}
              {officeLocations.map((office, idx) => (
                <div key={idx} className="bg-gradient-to-br from-green-50 to-[#fff8f0] p-6 rounded-2xl shadow-md border-l-4 border-[#ff9c00]">
                  <div className="flex items-start gap-4">
                    <div className="w-12 h-12 bg-gradient-to-br from-green-600 to-[#ff9c00] rounded-lg flex items-center justify-center text-white flex-shrink-0">
                      <Building className="w-6 h-6" />
                    </div>
                    <div>
                      <h3 className="text-xl font-bold text-gray-900 mb-1">{office.title}</h3>
                      <p className="text-sm text-[#ff9c00] font-semibold mb-2">{office.titleHindi}</p>
                      <p className="text-gray-700 mb-1">{office.address}</p>
                      <p className="text-gray-700 font-semibold mb-2">{office.state}</p>
                      <span className="inline-block bg-green-100 text-green-700 text-xs font-semibold px-3 py-1 rounded-full">
                        {office.type}
                      </span>
                    </div>
                  </div>
                </div>
              ))}

              {/* Company Details Card */}
              <div className="bg-white p-6 rounded-2xl shadow-lg border-2 border-green-600">
                <h3 className="text-2xl font-bold text-gray-900 mb-4 flex items-center gap-2">
                  <Globe className="w-6 h-6 text-green-600" />
                  Company Information
                </h3>
                <p className="text-lg text-[#ff9c00] font-semibold mb-4">कंपनी की जानकारी</p>
                <div className="space-y-3 text-gray-700">
                  <div className="flex justify-between border-b pb-2">
                    <span className="font-semibold">Company Name:</span>
                    <span className="text-right">Morvi Crop Science Pvt Ltd</span>
                  </div>
                  <div className="flex justify-between border-b pb-2">
                    <span className="font-semibold">CIN:</span>
                    <span className="text-right text-sm">U47737CT2023PTC015397</span>
                  </div>
                  <div className="flex justify-between border-b pb-2">
                    <span className="font-semibold">Established:</span>
                    <span>November 2023</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="font-semibold">Status:</span>
                    <span className="text-green-600 font-bold">Active</span>
                  </div>
                </div>
              </div>

              {/* Social Media */}
              <div className="bg-gradient-to-br from-green-600 to-[#ff9c00] p-6 rounded-2xl shadow-lg text-white">
                <h3 className="text-2xl font-bold mb-4">Follow Us</h3>
                <p className="text-lg font-semibold mb-4">हमें फॉलो करें</p>
                <div className="flex gap-4">
                  <button className="w-12 h-12 bg-white rounded-full flex items-center justify-center text-green-600 hover:scale-110 transition-transform">
                    <Facebook className="w-6 h-6" />
                  </button>
                  <button className="w-12 h-12 bg-white rounded-full flex items-center justify-center text-[#ff9c00] hover:scale-110 transition-transform">
                    <Twitter className="w-6 h-6" />
                  </button>
                  <button className="w-12 h-12 bg-white rounded-full flex items-center justify-center text-green-600 hover:scale-110 transition-transform">
                    <Instagram className="w-6 h-6" />
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* Map Section */}
      <section className="py-20 bg-gradient-to-br from-gray-50 to-white">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="text-center mb-12">
            <h2 className="text-4xl font-bold text-gray-900 mb-2">Find Us on Map</h2>
            <p className="text-2xl text-[#ff9c00] font-semibold">मानचित्र पर हमें खोजें</p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {/* West Bengal Map */}
            <div className="bg-white rounded-2xl shadow-lg overflow-hidden border-4 border-green-600">
              <div className="bg-green-600 text-white p-4">
                <h3 className="text-xl font-bold">West Bengal Office</h3>
                <p className="text-sm">Samudragarh, Purba Burdwan</p>
              </div>
              <div className="h-96 bg-gray-200 flex items-center justify-center">
                <div className="text-center">
                  <MapPin className="w-16 h-16 text-green-600 mx-auto mb-4" />
                  <p className="text-gray-600">Map Integration</p>
                  <p className="text-sm text-gray-500">Add Google Maps iframe here</p>
                </div>
              </div>
            </div>

            {/* Chhattisgarh Map */}
            <div className="bg-white rounded-2xl shadow-lg overflow-hidden border-4 border-[#ff9c00]">
              <div className="bg-[#ff9c00] text-white p-4">
                <h3 className="text-xl font-bold">Chhattisgarh Office</h3>
                <p className="text-sm">Ambikapur, Surguja</p>
              </div>
              <div className="h-96 bg-gray-200 flex items-center justify-center">
                <div className="text-center">
                  <MapPin className="w-16 h-16 text-[#ff9c00] mx-auto mb-4" />
                  <p className="text-gray-600">Map Integration</p>
                  <p className="text-sm text-gray-500">Add Google Maps iframe here</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* Quick Contact Banner */}
      <section className="py-16 bg-gradient-to-r from-green-600 to-[#ff9c00] text-white">
        <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
          <h2 className="text-3xl font-bold mb-2">Need Immediate Assistance?</h2>
          <p className="text-xl font-semibold mb-6">तत्काल सहायता चाहिए?</p>
          <div className="flex flex-col sm:flex-row gap-4 justify-center items-center">
            <a href="tel:+917987279783" className="bg-white text-green-700 px-8 py-4 rounded-full font-semibold hover:bg-green-50 transition-all transform hover:scale-105 shadow-lg flex items-center gap-2">
              <Phone className="w-5 h-5" />
              Call Now: +91 7987279783
            </a>
            <a href="mailto:morvicropscience@gmail.com" className="bg-transparent border-2 border-white text-white px-8 py-4 rounded-full font-semibold hover:bg-white hover:text-[#ff9c00] transition-all transform hover:scale-105 flex items-center gap-2">
              <Mail className="w-5 h-5" />
              Email Us
            </a>
          </div>
        </div>
      </section>
    </div>
  );
}